                              id=&quot;notes&quot;
                              class=&quot;w-full px-4 py-3 bg-gray-50 border-2 border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 transition-all resize-none&quot; 
                              rows=&quot;4&quot; 
