                        &lt;i class=&quot;fas fa-warehouse w-5&quot;&gt;&lt;/i&gt;
                        &lt;span x-show=&quot;sidebarOpen&quot;&gt;المخازن والجرد&lt;/span&gt;
                    &lt;/div&gt;
                    &lt;i x-show=&quot;sidebarOpen&quot; class=&quot;fas fa-chevron-down text-xs transition-transform duration-300&quot; 
                       :class=&quot;open ? &#039;rotate-180&#039; : &#039;&#039;&quot;&gt;&lt;/i&gt;
                &lt;/button&gt;
                &lt;div x-show=&quot;open&quot; 
                     x-collapse 
                     class=&quot;mr-8 mt-2 space-y-1&quot;&gt;
                    
                    &lt;a href=&quot;http://localhost/warehouses&quot; 
                       class=&quot;flex items-center gap-2 px-4 py-2 text-sm text-gray-300 hover:text-white hover:bg-gray-800 rounded-lg transition-all &quot;&gt;
