                        &lt;i class=&quot;fas fa-plus-circle text-xs&quot;&gt;&lt;/i&gt;
                        &lt;span&gt;إضافة منتج&lt;/span&gt;
                    &lt;/a&gt;

                    &lt;hr class=&quot;border-gray-700 my-2&quot;&gt;
                    
                    &lt;a href=&quot;http://localhost/products/bulk-price-update&quot; 
