    &lt;!-- Main Content --&gt;
    &lt;main :class=&quot;sidebarOpen ? &#039;mr-64&#039; : &#039;mr-20&#039;&quot; class=&quot;transition-all duration-300 min-h-screen&quot;&gt;
        
        &lt;!-- Top Bar --&gt;
        &lt;header class=&quot;bg-white shadow-sm sticky top-0 z-40&quot;&gt;
