    &lt;link href=&quot;https://fonts.googleapis.com/css2?family=Cairo:wght@300;400;600;700;900&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;
    
    &lt;style&gt;
        * {
            font-family: &#039;Cairo&#039;, sans-serif;
        }
        
        .sidebar-scrollbar::-webkit-scrollbar {
            width: 5px;
        }
        
        .sidebar-scrollbar::-webkit-scrollbar-track {
            background: #1f2937;
        }
        
        .sidebar-scrollbar::-webkit-scrollbar-thumb {
            background: #4b5563;
            border-radius: 10px;
        }
        
        .sidebar-scrollbar::-webkit-scrollbar-thumb:hover {
            background: #6b7280;
        }

        @keyframes slideIn {
            from {
                opacity: 0;
                transform: translateY(-10px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }

        @keyframes slideInRight {
            from {
                opacity: 0;
                transform: translateX(20px);
            }
            to {
                opacity: 1;
                transform: translateX(0);
            }
        }

        .animate-slide-in {
            animation: slideIn 0.3s ease-out;
        }

        .animate-slide-in-right {
            animation: slideInRight 0.3s ease-out;
        }

        .gradient-bg {
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
        }

        .hover-scale {
            transition: transform 0.2s;
        }

        .hover-scale:hover {
            transform: scale(1.05);
        }

        .menu-active {
            position: relative;
        }

        .menu-active::before {
            content: &#039;&#039;;
            position: absolute;
            right: 0;
            top: 50%;
            transform: translateY(-50%);
            width: 4px;
            height: 70%;
            background: linear-gradient(to bottom, #3b82f6, #8b5cf6);
            border-radius: 0 4px 4px 0;
        }
    &lt;/style&gt;

    &lt;style&gt;
    @import url(&#039;https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;800&amp;family=Tajawal:wght@400;500;700&amp;display=swap&#039;);
    
    :root {
        --primary-gradient: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
        --success-gradient: linear-gradient(135deg, #11998e 0%, #38ef7d 100%);
        --info-gradient: linear-gradient(135deg, #4facfe 0%, #00f2fe 100%);
        --warning-gradient: linear-gradient(135deg, #fa709a 0%, #fee140 100%);
        --danger-gradient: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
        --dark-bg: #1a1d29;
        --card-bg: #ffffff;
        --text-primary: #2d3748;
        --text-secondary: #718096;
        --border-color: #e2e8f0;
    }
    
    body {
        font-family: &#039;Tajawal&#039;, sans-serif;
        background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%);
        min-height: 100vh;
    }
    
    .page-header {
        background: var(--dark-bg);
        padding: 2rem;
        border-radius: 20px;
        margin-bottom: 2rem;
        position: relative;
        overflow: hidden;
    }
    
    .page-header::before {
        content: &#039;&#039;;
        position: absolute;
        top: -50%;
        right: -50%;
        width: 200%;
        height: 200%;
        background: radial-gradient(circle, rgba(102, 126, 234, 0.1) 0%, transparent 70%);
        animation: pulse 4s ease-in-out infinite;
    }
    
    @keyframes pulse {
        0%, 100% { transform: scale(1); opacity: 0.5; }
        50% { transform: scale(1.1); opacity: 0.8; }
    }
    
    .page-title {
        font-family: &#039;Cairo&#039;, sans-serif;
        font-size: 2.5rem;
        font-weight: 800;
        color: white;
        margin: 0;
        position: relative;
        z-index: 1;
        text-shadow: 2px 2px 4px rgba(0,0,0,0.2);
    }
    
    .page-subtitle {
        color: rgba(255,255,255,0.8);
        margin-top: 0.5rem;
        position: relative;
        z-index: 1;
        font-size: 1.1rem;
    }
    
    .stats-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
        gap: 1.5rem;
        margin-bottom: 2rem;
    }
    
    .stat-card {
        background: var(--card-bg);
        border-radius: 20px;
        padding: 2rem;
        position: relative;
        overflow: hidden;
        box-shadow: 0 10px 40px rgba(0,0,0,0.08);
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        border: 1px solid rgba(255,255,255,0.8);
    }
    
    .stat-card::before {
        content: &#039;&#039;;
        position: absolute;
        top: 0;
        left: 0;
        right: 0;
        height: 5px;
        background: var(--gradient);
        transform: scaleX(0);
        transition: transform 0.3s ease;
        transform-origin: left;
    }
    
    .stat-card:hover {
        transform: translateY(-8px);
        box-shadow: 0 20px 60px rgba(0,0,0,0.15);
    }
    
    .stat-card:hover::before {
        transform: scaleX(1);
    }
    
    .stat-card.cash { --gradient: var(--success-gradient); }
    .stat-card.bank { --gradient: var(--info-gradient); }
    .stat-card.total { --gradient: var(--primary-gradient); }
    .stat-card.transactions { --gradient: var(--warning-gradient); }
    
    .stat-icon {
        width: 60px;
        height: 60px;
        border-radius: 15px;
        background: var(--gradient);
        display: flex;
        align-items: center;
        justify-content: center;
        margin-bottom: 1rem;
        box-shadow: 0 8px 16px rgba(0,0,0,0.15);
    }
    
    .stat-icon svg {
        width: 30px;
        height: 30px;
        color: white;
    }
    
    .stat-label {
        font-size: 0.95rem;
        color: var(--text-secondary);
        margin-bottom: 0.5rem;
        font-weight: 500;
    }
    
    .stat-value {
        font-family: &#039;Cairo&#039;, sans-serif;
        font-size: 2rem;
        font-weight: 800;
        color: var(--text-primary);
        margin-bottom: 0.5rem;
        direction: ltr;
        text-align: right;
    }
    
    .filters-section {
        background: white;
        border-radius: 20px;
        padding: 1.5rem;
        margin-bottom: 2rem;
        box-shadow: 0 10px 40px rgba(0,0,0,0.08);
    }
    
    .filters-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
        gap: 1rem;
        margin-top: 1rem;
    }
    
    .filter-group {
        display: flex;
        flex-direction: column;
        gap: 0.5rem;
    }
    
    .filter-label {
        font-weight: 600;
        color: var(--text-secondary);
        font-size: 0.875rem;
    }
    
    .filter-input {
        padding: 0.75rem;
        border: 2px solid var(--border-color);
        border-radius: 10px;
        font-family: inherit;
        transition: all 0.3s ease;
    }
    
    .filter-input:focus {
        outline: none;
        border-color: #667eea;
        box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
    }
    
    .action-btn {
        padding: 0.75rem 1.5rem;
        border: none;
        border-radius: 12px;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.3s ease;
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 0.5rem;
        background: var(--primary-gradient);
        color: white;
        box-shadow: 0 4px 15px rgba(102, 126, 234, 0.4);
    }
    
    .action-btn:hover {
        transform: translateY(-2px);
        box-shadow: 0 6px 20px rgba(0,0,0,0.25);
    }
    
    .transactions-container {
        background: white;
        border-radius: 20px;
        overflow: hidden;
        box-shadow: 0 10px 40px rgba(0,0,0,0.08);
    }
    
    .table-header {
        padding: 1.5rem;
        background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
        color: white;
    }
    
    .table-title {
        font-family: &#039;Cairo&#039;, sans-serif;
        font-size: 1.5rem;
        font-weight: 700;
        margin: 0;
    }
    
    .transactions-table {
        width: 100%;
        border-collapse: collapse;
    }
    
    .transactions-table thead {
        background: #f7fafc;
        border-bottom: 2px solid var(--border-color);
    }
    
    .transactions-table th {
        padding: 1rem;
        text-align: right;
        font-weight: 700;
        color: var(--text-primary);
        font-size: 0.875rem;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }
    
    .transactions-table tbody tr {
        border-bottom: 1px solid var(--border-color);
        transition: all 0.2s ease;
    }
    
    .transactions-table tbody tr:hover {
        background: #f7fafc;
    }
    
    .transactions-table td {
        padding: 1rem;
        color: var(--text-primary);
        font-size: 0.95rem;
    }
    
    .badge {
        display: inline-block;
        padding: 0.35rem 0.75rem;
        border-radius: 20px;
        font-size: 0.8rem;
        font-weight: 600;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }
    
    .badge.income {
        background: #d1fae5;
        color: #065f46;
    }
    
    .badge.expense {
        background: #fee2e2;
        color: #991b1b;
    }
    
    .amount-in {
        color: #10b981;
        font-weight: 700;
        font-family: &#039;Cairo&#039;, sans-serif;
    }
    
    .amount-out {
        color: #ef4444;
        font-weight: 700;
        font-family: &#039;Cairo&#039;, sans-serif;
    }
    
    .pagination-wrapper {
        padding: 1.5rem;
        display: flex;
        justify-content: center;
    }
    
    @media (max-width: 768px) {
        .stats-grid {
            grid-template-columns: 1fr;
        }
        .page-title {
            font-size: 2rem;
        }
    }
&lt;/style&gt;
&lt;/head&gt;
&lt;body class=&quot;bg-gray-50&quot; x-data=&quot;{ sidebarOpen: true }&quot;&gt;
    
    &lt;!-- Sidebar --&gt;
    &lt;aside :class=&quot;sidebarOpen ? &#039;w-64&#039; : &#039;w-20&#039;&quot; 
           class=&quot;fixed right-0 top-0 h-screen bg-gray-900 text-white transition-all duration-300 z-50 sidebar-scrollbar overflow-y-auto&quot;&gt;
        
        &lt;!-- Logo &amp; Toggle --&gt;
        &lt;div class=&quot;p-4 flex items-center justify-between border-b border-gray-800&quot;&gt;
            &lt;div x-show=&quot;sidebarOpen&quot; class=&quot;flex items-center gap-3 animate-slide-in-right&quot;&gt;
